#include <bits/stdc++.h> 
using namespace std;
#define ll long long
const int N=1000005;
int n,p,fir;
ll mx,tmp,mx2;
bool flag=0;
int main()
{
	cin>>n>>p>>fir;
	tmp=max(fir,0);
	mx=fir;
	mx2=fir+fir;
    flag = fir >0&&n>1;
	for(int i=2;i<n;i++)
	{
		int num;
		cin>>num;
		tmp+=num;
		mx=max(mx,tmp);
		mx2+=max(mx,0ll);
		if(flag) mx2%=p;
		if(mx2>fir) flag=1;
		tmp=max(tmp,0ll);
	}
    ll ans = flag ? mx2 : fir;
    if (ans < 0) cout<<'-';
	// if(flag) cout<<mx2;
	// else cout<<fir;
    cout<<abs(ans) % p;
	return 0;
}
